export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二十點三十分。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "燈先死了。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是一盞一盞地滅——是整片。天花板上的日光燈管同時熄掉，像有人把開關一次扳到底。黑暗只持續了大約兩秒。然後備用電源接上了。昏黃的。從牆壁高處那兩盞電池燈裡吐出來的，帶著一層暖濁的光，把整間醫務室染成了醫院深夜走廊的那種顏色——不是黑暗，但也不是亮。是一種讓人分不清東西原本是什麼顏色的光。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "空調停了。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有第一時間注意到。但在空調的嗡嗡聲消失之後，房間裡突然多出了很多聲音——雨打在窗玻璃上的、風灌進通風口的、遠處發電機低沉的轟鳴、以及一種被這些聲音壓在底下的、他一直沒聽見過的沉默。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊裡有人跑過去。腳步急促。對講機的沙沙聲。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "南翼部分區域電力切換，請現場人員待在安全位置，避免自行移動。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言坐在內間的病床上，雙腳垂在床沿。他盯著天花板上那盞昏黃的備用燈，等了三秒。然後站起來。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)停電了。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)南翼局部停電。廣播說「部分區域」——不是全校。只是這一棟。只是這一側。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走到內間和外間之間的門邊，推開。外間也切到了備用電。保健老師的桌上那盞小檯燈還亮著，光也是黃的。登記簿攤開在桌面上，筆擱在旁邊。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保健老師正站在桌前，手裡拿著對講機，眉頭皺著。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.HealthTeacher, character: "保健老師", dialogue: "⋯⋯好，我知道了。南翼配電跳閘，備用電已切。禮堂那邊也受影響了？好，我先確認這邊的學生沒事。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.HealthTeacher_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她放下對講機，看見顧言站在內間門口。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.HealthTeacher, character: "保健老師", dialogue: "停電了，配電箱跳閘。你先待在裡面不要動，應急燈亮著。我去外面看看情況，馬上回來。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.HealthTeacher_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯好。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她快步走出正門。走廊上的聲音變得嘈雜——對講機、腳步、有人在喊什麼。然後她又回來了，不到兩分鐘，臉上帶著一點不安。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.HealthTeacher, character: "保健老師", dialogue: "走廊盡頭的防火門自動落下了，停電觸發的。我推不開，要等電力恢復或者維修組來。你先別出去，走廊暗，不好走。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.HealthTeacher_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她回到外間桌前，拿起電話撥了幾個號碼。忙線。又撥。忙線。她放下電話，拿起對講機繼續聯絡。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他回到內間，走向後門。後門在內間的另一側，通向南翼外牆的設備平台。門上貼著一張打印紙，字跡被潮氣弄得有些暈開：", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「防颱期間禁止開啟，違者自負。」", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門框邊緣貼著寬幅的灰色膠帶——那種他在鐘樓臨時告示邊角見過的、在裝卸區器材箱上見過的灰色膠帶——把門縫封了個嚴實。不止膠帶。門把手上纏了兩圈尼龍紮帶，上面掛著一個紙標籤：「颱風封條，請勿開啟。」", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯不一樣了。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)下午我看過這扇門。紅底貼紙，四個角用膠帶加固，一個老式壓把鎖。現在——打印紙換了，字不一樣。灰色膠帶封了整個門框。尼龍紮帶纏了門把。從「請勿開啟」變成了「違者自負」。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)有人來加強過。從外面。在我待在這個房間的這幾個小時裡。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)後門也封了。而且比我進來的時候封得更死。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)防颱封條。灰色膠帶。尼龍紮帶。每一樣都是防颱規定裡會有的東西。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)走廊防火門停電自動落下——消防的。後門有防颱封條——防風的。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)兩個方向都被封了。沒有一個是惡意的。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外間傳來保健老師打電話的聲音。她撥了指揮室的內線——忙線。撥校安值班室——無人接聽。她又撥了幾個號碼，每一個都是忙線或者無人接聽。她放下電話，拿起對講機，裡面傳來斷斷續續的呼叫聲，蓋過了她的聲音。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她打不通。指揮室忙線。校安無人接。對講機全是碎片。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他掏出手機。螢幕右上角的訊號格——一格。一格在閃爍，像隨時會消失。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一格訊號。下午還是三格。停電加上颱風，訊號掉了。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他打開訊息界面，輸入了三個字：「我在哪」。發送。轉圈。轉圈。轉圈。紅色驚嘆號。發送失敗。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊號不夠。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)內線忙。手機沒訊號。兩種通訊都斷了。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在內間門口，看著外間保健老師的背影。她還在打電話。雨聲像一堵牆，把所有遠處的聲音都隔在外面。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)走廊防火門——停電落下。後門——防颱封條。電話——忙線和無人接聽。手機——一格訊號，發不出訊息。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)每一道障礙，單獨看，都合理。防火門是消防的。封條是防颱的。忙線是因為全校都在打電話。訊號差是因為颱風。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)合在一起——", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我出不去。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走回內間。經過窗邊時停下了腳步。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗戶是毛玻璃的。貼了十字交叉的灰色防颱膠帶，從裡面看出去，整面窗戶像被蜘蛛網覆蓋，只有膠帶之間的縫隙能透出模糊的光影。窗戶外側加了一道半高的防颱板——木板，大約遮住窗戶下面三分之二的面積。上面三分之一仍然露出玻璃，但被膠帶和雨幕覆蓋得幾乎看不穿。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外。雨。黑暗。以及——", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)聲音。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從窗戶上方那個舊式通風百葉口傳進來的。不是雨聲。是一種更低沉的、持續的、帶著節奏的機械聲。柴油發電機的運轉聲。就在外面。很近。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他聞到了。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)油味。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "淡淡的。不是刺鼻的那種——像有人在一個密閉的車庫裡發動了引擎，隔了很久之後，油味才慢慢滲進來的那種。混合著潮濕的塑膠味、悶熱的空氣、以及一種說不上來的、悶在喉嚨裡的感覺。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)發電機。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)外面有發電機在運轉。味道從通風口進來了。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他回想下午在醫務室窗邊看到的情景——南翼外牆的設備平台。那個平台平常是空的，只放一些空調外機。但下午他看到有人在上面搬東西。抽水泵。臨時發電機。纜線。塑膠布。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)維修組把設備搬到了平台上。因為低處積水，設備不能放在地面。所以搬到高處。高處——就是醫務室外牆這邊。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)發電機的排氣口，正對著醫務室的通風百葉。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)平常不會有問題。通風口是向外排的。但現在——", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走到通風口下面，仰頭看。百葉口的金屬葉片外面，有一層東西在抖動。塑膠布。被風吹得一鼓一癟、一鼓一癟。每一次鼓起來的時候，空氣就被往裡面壓一次。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)塑膠布。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)防颱塑膠布。搭在設備和牆面之間，本來是遮雨用的。但風向變了——暴雨把塑膠布吹成了漏斗形。外面的風把塑膠布往通風口方向壓。發電機的廢氣被風和塑膠布一起往百葉口裡送。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)廢氣不是散到外面的。是被壓回來的。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他退後一步。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)油味。悶。潮濕。塑膠。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這些是我聞得到的。真正讓我頭暈的東西，我聞不到。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一氧化碳沒有味道。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二十點三十八分。顧言站在內間中央。四周很安靜——不，不對，四周一點都不安靜。雨聲、發電機聲、通風口塑膠布的拍打聲、遠處廣播的回聲、還有一種來自他自己呼吸的、越來越粗重的喘息。但這些聲音加在一起，反而構成了一種奇怪的、悶罐一樣的安靜——什麼都在響，但什麼都傳不出去。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)每一道障礙單獨看都合理。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)合在一起，就變成籠子。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他閉上眼。雨聲在耳膜上敲。油味在鼻腔裡轉。昏黃的備用燈透過眼皮，把視野染成一片不安全的琥珀色。", background: Background.Chapter_3_Ch3_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不能待在這裡不動。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)要出去。任何一扇門。任何一個方向。出去。", background: Background.Chapter_3_Ch3_Act13_S0, portrait: Portrait.GuYan_Determined },
];
